mapper.select:
/* com.shop.mapper.biz.notice.selectNoticeListPaging */ SELECT ROW_NUMBER() OVER(ORDER BY A.ID DESC) AS no, A.ID AS id, A.NOTICE_CD AS noticeCd, A.TITLE AS title, A.MOVE_URI AS moveUri, A.GESI_YN AS gesiYn, A.CRE_TM AS creTm, A.UPD_TM AS updTm, A.UPD_USER AS updUser, (SELECT COUNT(D.ID) AS C FROM TB_FILE_DET D WHERE D.FILE_ID = A.FILE_ID AND D.DEL_YN = 'N') AS fileCnt, COALESCE((SELECT X.USER_NM FROM TB_USER X WHERE A.CRE_USER = X.LOGIN_ID), A.CRE_USER) AS creUser, COUNT(*) OVER() AS totalRowCount FROM TB_NOTICE A WHERE A.DEL_YN = 'N'
AND PARTNER_ID = #{filter.partnerId}
AND TITLE LIKE CONCAT('%', #{filter.title}, '%')
AND CRE_TM BETWEEN #{filter.startDate} AND #{filter.endDate}
AND NOTICE_CD = #{filter.noticeCd}
ORDER BY ID DESC LIMIT #{pageRowCount} OFFSET (#{curPage} - 1) * #{pageRowCount}

mapper.insert:
/* com.shop.mapper.Notice.insertNotice */
INSERT INTO TB_NOTICE (
    NOTICE_CD, PARTNER_ID, TITLE, FILE_ID, MOVE_URI, GESI_YN,
    CRE_USER, CRE_TM, UPD_USER, UPD_TM
) VALUES (
    #{noticeCd}, #{partnerId}, #{title}, #{fileId}, #{moveUri}, COALESCE(#{gesiYn}, 'N'),
    #{creUser}, NOW(), #{updUser}, NOW()
)

/* com.shop.mapper.Notice.insertPopupNotice */
INSERT INTO TB_NOTICE (NOTICE_CD, PARTNER_ID, TITLE, FILE_ID, MOVE_URI, GESI_YN, CRE_USER, UPD_USER)
VALUES ('1', #{partnerId}, #{title}, #{fileId}, #{moveUri}, COALESCE(#{gesiYn}, 'N'), #{creUser}, #{creUser})

mapper.update:
/* com.shop.mapper.Notice.updatePopupNoticeGesiYn */
UPDATE TB_NOTICE
SET GESI_YN  = #{gesiYn},
    UPD_USER = #{updUser},
    UPD_TM   = NOW()
WHERE ID = #{id}

/* com.shop.mapper.Notice.deletePopupNotice */
UPDATE TB_NOTICE
SET DEL_YN   = 'Y',
    UPD_USER = #{updUser},
    UPD_TM   = NOW()
WHERE ID = #{id}
